const profiles = $input.all()[0].json;
const arr = Array.isArray(profiles) ? profiles : [];
const linkedin = arr.find(p => p.service === 'linkedin' || p.service === 'linkedin_personal');
if (!linkedin) {
  throw new Error('No LinkedIn profile found in Buffer. Connect LinkedIn at buffer.com first.');
}
return [{ json: { profile_id: linkedin.id, username: linkedin.service_username || linkedin.formatted_username } }];

const input = $input.all()[0].json;
const posts = Array.isArray(input) ? input : (input.updates || []);
const sevenDaysAgo = Date.now() - (7 * 24 * 60 * 60 * 1000);

const recent = posts.filter(p => (p.sent_at ? p.sent_at * 1000 : 0) > sevenDaysAgo);

if (recent.length === 0) {
  return [{ json: { period: '7_days', pulled_at: new Date().toISOString(), post_count: 0, message: 'No posts in the last 7 days' } }];
}

const withMetrics = recent.map(p => {
  const s = p.statistics || {};
  const reactions = (s.likes || 0) + (s.reactions || 0);
  const comments = s.comments || 0;
  const shares = (s.shares || 0) + (s.reposts || 0);
  const impressions = Math.max(s.impressions || s.reach || 1, 1);
  const engRate = parseFloat(((reactions + comments + shares) / impressions * 100).toFixed(2));
  const text = p.text || '';
  const format = /^\d\.\s/.test(text) ? 'numbered_list'
    : text.startsWith('\u2022') || text.startsWith('-') ? 'bullet_list'
    : (text.match(/\n\n/g) || []).length >= 3 ? 'thread_style'
    : text.length < 280 ? 'short' : 'long_form';
  return {
    text_preview: text.slice(0, 200),
    sent_at: new Date(p.sent_at * 1000).toISOString().slice(0, 10),
    reactions, comments, shares, impressions,
    engagement_rate_pct: engRate, format
  };
});

const sorted = [...withMetrics].sort((a, b) => b.engagement_rate_pct - a.engagement_rate_pct);
const formatCounts = {};
withMetrics.forEach(p => { formatCounts[p.format] = (formatCounts[p.format] || 0) + 1; });
const topFormat = Object.entries(formatCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || 'unknown';
const totalImpressions = withMetrics.reduce((s, p) => s + p.impressions, 0);
const totalEngagement = withMetrics.reduce((s, p) => s + p.reactions + p.comments + p.shares, 0);
const avgRate = parseFloat((totalEngagement / Math.max(totalImpressions, 1) * 100).toFixed(2));

return [{ json: {
  period: '7_days',
  pulled_at: new Date().toISOString(),
  post_count: recent.length,
  total_impressions: totalImpressions,
  avg_engagement_rate_pct: avgRate,
  top_format: topFormat,
  format_breakdown: formatCounts,
  top_3_posts: sorted.slice(0, 3),
  bottom_3_posts: sorted.slice(-3),
  all_posts: withMetrics
} }];

const analytics = $input.all()[0].json;
const response = await fetch('http://100.99.6.88:8787/api/linkedin-analytics', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(analytics)
});
if (!response.ok) {
  throw new Error(`Dashboard save failed: ${response.status} ${await response.text()}`);
}
const result = await response.json();
return [{ json: { ...result, pulled_at: analytics.pulled_at, post_count: analytics.post_count } }];
